customCSS:
/* CRT Monitor Effect */
@import url('https://fonts.googleapis.com/css2?family=VT323&family=Fira+Code:wght@400;500&display=swap');

.scan-line {
  background: linear-gradient(
    to bottom,
    transparent 0%,
    rgba(0, 255, 0, 0.05) 50%,
    transparent 100%
  );
  animation: scanLines 4s linear infinite;
}

/* Terminal-style borders */
.stat-card,
.miner-card,
.health-card {
  border: 1px solid #00ff00;
  border-radius: 0;
}

.stat-card::before {
  background: #00ff00;
}

/* Clean stat values - no glow */
.stat-value {
  text-shadow: none;
}

/* Phosphor glow on cards */
.stat-card:hover,
.miner-card:hover {
  box-shadow: 
    0 0 10px rgba(0, 255, 0, 0.3),
    inset 0 0 20px rgba(0, 255, 0, 0.05);
}

/* Override celebration colors */
.celebration-icon {
  filter: hue-rotate(120deg) brightness(1.5);
}

.celebration-title {
  color: #00ff00 !important;
  text-shadow: 0 0 20px #00ff00, 0 0 40px #00ff00 !important;
}

/* Terminal-style header */
.logo::before {
  content: '> ';
  color: #00ff00;
}

/* Flicker effect */
@keyframes flicker {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.98; }
  51% { opacity: 0.95; }
  52% { opacity: 1; }
}

body {
  animation: flicker 0.15s infinite;
}
